&lt;!DOCTYPE html&gt;
&lt;html lang=&quot;sd&quot; dir=&quot;rtl&quot;&gt;
&lt;head&gt;
&lt;meta charset=&quot;UTF-8&quot;&gt;
&lt;meta name=&quot;viewport&quot; content=&quot;width=device-width, initial-scale=1.0&quot;&gt;
&lt;title&gt;مهيني جا بهترين شاگرد - GBHSS نئون ديرو&lt;/title&gt;
&lt;link href=&quot;https://fonts.googleapis.com/css2?family=Inter:opsz,wght@14..32,300;14..32,400;14..32,500;14..32,600;14..32,700;14..32,800;14..32,900&amp;family=Playfair+Display:wght@500;600&amp;display=swap&quot; rel=&quot;stylesheet&quot;&gt;
&lt;link href=&quot;https://fonts.googleapis.com/css2?family=Noto+Naskh+Arabic:wght@400;500;600;700&amp;display=swap&quot; rel=&quot;stylesheet&quot;&gt;
&lt;link rel=&quot;stylesheet&quot; href=&quot;https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.5.0/css/all.min.css&quot;&gt;
&lt;style&gt;
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body {
    background: #cecece;
    display: flex; justify-content: center; align-items: flex-start;
    padding: 20px; font-family: &apos;Noto Naskh Arabic&apos;, serif; direction: rtl;
  }
  .fb-post-wrapper {
    width: 1080px; height: 1350px; background: #ffffff; overflow: visible;
    box-shadow: 0 10px 50px rgba(0,0,0,0.32); border: 2px solid #b8b8b8;
    display: flex; flex-direction: column; direction: rtl;
  }


  /* ===== HEADER ===== */
  .header-top-space {
    width: 100%; height: 28px; background: #ffffff;
    position: relative; z-index: 5; flex-shrink: 0;
  }
  .header-container {
    width: 100%; flex-shrink: 0;
    background: linear-gradient(135deg, #083d22 0%, #08a451 45%, #0aad56 55%, #083d22 100%);
    position: relative; overflow: visible; z-index: 10;
  }
  .header-container::after {
    content: &apos;&apos;; position: absolute; inset: 0;
    background: radial-gradient(ellipse at 20% 50%, rgba(252,202,19,0.10) 0%, transparent 55%);
    pointer-events: none; z-index: 1;
  }
  .header-stripe { width: 100%; height: 9px; display: flex; position: relative; z-index: 0; }
  .header-stripe span { flex: 1; }
  .header-stripe span:nth-child(1) { background: #fcca13; }
  .header-stripe span:nth-child(2) { background: #08a451; }
  .header-stripe span:nth-child(3) { background: #eb1f25; }
  .header-stripe span:nth-child(4) { background: #703336; }
  .header-inner {
    display: flex; align-items: center; justify-content: center;
    padding: 14px 44px 10px; gap: 28px;
    position: relative; z-index: 2;
    flex-direction: row; direction: ltr;
  }
  .header-logo {
    flex-shrink: 0; width: 165px; height: 165px; border-radius: 50%;
    background: transparent; border: none;
    display: flex; align-items: center; justify-content: center;
    position: relative; z-index: 20;
    margin-top: -45px; margin-bottom: -45px;
    filter: drop-shadow(0 8px 24px rgba(0,0,0,0.40))
            drop-shadow(0 2px 8px rgba(0,0,0,0.24));
  }
  .header-logo img { width: 100%; height: 100%; object-fit: contain; display: block; }
  .header-text { flex: 1; text-align: center; direction: rtl; }
  .school-name-main {
    font-family: &apos;Noto Naskh Arabic&apos;, serif;
    font-size: 34px; font-weight: 700; color: #ffffff;
    line-height: 1.55; text-shadow: 0 2px 10px rgba(0,0,0,0.36);
  }
  .school-tagline {
    font-family: &apos;Noto Naskh Arabic&apos;, serif;
    font-size: 15px; color: rgba(252,202,19,0.90); margin-top: 5px;
  }
  .header-bottom-stripe { width: 100%; height: 5px; display: flex; position: relative; z-index: 0; }
  .header-bottom-stripe span { flex: 1; }
  .header-bottom-stripe span:nth-child(1) { background: #703336; }
  .header-bottom-stripe span:nth-child(2) { background: #eb1f25; }
  .header-bottom-stripe span:nth-child(3) { background: #08a451; }
  .header-bottom-stripe span:nth-child(4) { background: #fcca13; }


  /* ===== BANNER ===== */
  .page-banner {
    width: 100%; flex-shrink: 0; padding: 14px 44px;
    display: flex; align-items: center; justify-content: center; gap: 14px;
    position: relative; z-index: 5;
  }
  .page-banner.toppers {
    background: linear-gradient(135deg, #8a6200 0%, #c8900a 35%, #daa520 50%, #c8900a 65%, #8a6200 100%);
  }
  .page-banner-line { flex: 1; height: 2px; background: rgba(255,255,255,0.35); border-radius: 2px; }
  .page-banner-icon { font-size: 24px; color: #fff7dc; flex-shrink: 0; }
  .page-banner-title {
    font-family: &apos;Noto Naskh Arabic&apos;, serif;
    font-size: 26px; font-weight: 700; color: #ffffff;
    text-shadow: 0 1px 4px rgba(0,0,0,0.25);
  }


  /* ===== BODY ===== */
  .body-container {
    flex: 1; padding: 16px 46px;
    display: flex; flex-direction: column; overflow: hidden;
  }
  .body-card {
    flex: 1;
    background: linear-gradient(160deg, #fffef5 0%, #f9fafc 100%);
    border: 1.5px solid #e8dec0; border-radius: 14px;
    padding: 16px 28px 14px;
    display: flex; flex-direction: column; overflow: hidden;
  }


  /* META ROW */
  .meta-row {
    display: flex; justify-content: center; align-items: stretch;
    gap: 10px; margin-bottom: 10px;
    direction: ltr;
  }
  .meta-chip {
    background: #ffffff; border: 1.5px solid #e5e9ee;
    border-radius: 10px; padding: 6px 16px;
    display: flex; flex-direction: row; align-items: center; gap: 10px;
    direction: rtl;
  }
  .meta-icon {
    width: 32px; height: 32px; border-radius: 50%;
    display: flex; align-items: center; justify-content: center;
    font-size: 13px; color: #fff; flex-shrink: 0;
  }
  .meta-icon.teacher { background: linear-gradient(135deg, #08a451, #066e36); }
  .meta-icon.subject { background: linear-gradient(135deg, #703336, #8a4245); }
  .meta-icon.month   { background: linear-gradient(135deg, #2596be, #1a7a9e); }
  .meta-icon.cls     { background: linear-gradient(135deg, #b8860b, #d4a800); }
  .meta-icon.marks   { background: linear-gradient(135deg, #eb1f25, #b8161c); }
  .meta-chip-text { text-align: right; }
  .meta-chip-label {
    font-family: &apos;Noto Naskh Arabic&apos;, serif;
    font-size: 11px; font-weight: 600; color: #9ca3af;
  }
  .meta-chip-val {
    font-family: &apos;Noto Naskh Arabic&apos;, serif;
    font-size: 15px; font-weight: 700; color: #111827; margin-top: 1px;
  }


  /* CONGRATULATIONS BANNER */
  .congrats-banner {
    background: linear-gradient(135deg, #083d22 0%, #08a451 50%, #083d22 100%);
    border-radius: 12px; padding: 11px 24px;
    text-align: center; margin-bottom: 12px;
    position: relative; overflow: hidden;
  }
  .congrats-banner::after {
    content: &apos;&apos;; position: absolute; inset: 0;
    background: radial-gradient(ellipse at 50% 50%, rgba(252,202,19,0.15) 0%, transparent 70%);
    pointer-events: none;
  }
  .congrats-banner-stars {
    font-size: 16px; color: #fcca13; letter-spacing: 10px;
    margin-bottom: 3px; position: relative; z-index: 2;
  }
  .congrats-banner-text {
    font-family: &apos;Noto Naskh Arabic&apos;, serif;
    font-size: 20px; font-weight: 700; color: #ffffff;
    position: relative; z-index: 2;
    text-shadow: 0 1px 4px rgba(0,0,0,0.3);
  }
  .congrats-banner-sub {
    font-family: &apos;Noto Naskh Arabic&apos;, serif;
    font-size: 13px; font-weight: 500;
    color: rgba(252,202,19,0.90); margin-top: 2px;
    position: relative; z-index: 2;
  }


  /* PODIUM ROW */
  .podium-row {
    display: flex; align-items: flex-end; justify-content: center;
    gap: 20px; margin-bottom: 14px; flex-shrink: 0;
  }
  .topper-card {
    display: flex; flex-direction: column; align-items: center; position: relative;
  }
  .topper-card.pos-1 { order: 2; }
  .topper-card.pos-2 { order: 1; }
  .topper-card.pos-3 { order: 3; }


  .rank-badge {
    position: absolute; top: -10px; left: -6px; z-index: 5;
    width: 42px; height: 42px; border-radius: 50%;
    display: flex; align-items: center; justify-content: center;
    font-family: &apos;Inter&apos;, sans-serif; font-size: 14px; font-weight: 900; color: #fff;
    border: 3px solid #fff; box-shadow: 0 3px 10px rgba(0,0,0,0.28);
  }
  .topper-card.pos-1 .rank-badge {
    background: linear-gradient(135deg, #FFD700, #FFA500);
    width: 50px; height: 50px; font-size: 17px; top: -14px; left: -8px;
  }
  .topper-card.pos-2 .rank-badge { background: linear-gradient(135deg, #B0B0B0, #909090); }
  .topper-card.pos-3 .rank-badge { background: linear-gradient(135deg, #CD7F32, #a0622a); }


  .crown-icon {
    position: absolute; top: -28px; left: 50%; transform: translateX(-50%);
    font-size: 30px; color: #FFD700; z-index: 6;
    filter: drop-shadow(0 2px 4px rgba(0,0,0,0.28));
  }


  .topper-photo {
    border-radius: 50%; overflow: hidden;
    display: flex; align-items: center; justify-content: center;
    position: relative; margin-bottom: 10px; flex-shrink: 0;
  }
  .topper-card.pos-1 .topper-photo {
    width: 178px; height: 178px; border: 6px solid #FFD700;
    box-shadow: 0 0 0 4px rgba(255,215,0,0.22), 0 8px 24px rgba(0,0,0,0.18);
  }
  .topper-card.pos-2 .topper-photo,
  .topper-card.pos-3 .topper-photo {
    width: 148px; height: 148px; border: 5px solid #B0B0B0;
    box-shadow: 0 0 0 3px rgba(176,176,176,0.20), 0 6px 16px rgba(0,0,0,0.14);
  }
  .topper-card.pos-3 .topper-photo { border-color: #CD7F32; }
  .topper-photo img {
    width: 100%; height: 100%; object-fit: cover; object-position: top center; border-radius: 50%;
  }
  .topper-name {
    font-family: &apos;Noto Naskh Arabic&apos;, serif;
    font-size: 18px; font-weight: 700; color: #111827;
    text-align: center; margin-bottom: 2px;
  }
  .topper-card.pos-1 .topper-name { font-size: 21px; }
  .topper-class {
    font-family: &apos;Noto Naskh Arabic&apos;, serif;
    font-size: 13px; color: #08a451; text-align: center; margin-bottom: 6px;
  }
  .tmc {
    background: #fff; border: 1.5px solid #e5e8ec;
    border-radius: 8px; padding: 5px 16px; text-align: center;
  }
  .tmc-label {
    font-family: &apos;Noto Naskh Arabic&apos;, serif;
    font-size: 10px; font-weight: 600; color: #9ca3af;
  }
  .tmc-val { font-family: &apos;Inter&apos;, sans-serif; font-size: 18px; font-weight: 800; }
  .topper-card.pos-1 .tmc-val { color: #b8860b; }
  .topper-card.pos-2 .tmc-val { color: #707070; }
  .topper-card.pos-3 .tmc-val { color: #CD7F32; }


  /* MENTIONS TITLE */
  .mentions-title {
    font-family: &apos;Noto Naskh Arabic&apos;, serif;
    font-size: 15px; font-weight: 700; color: #703336;
    text-align: center; margin-bottom: 10px;
  }
  .mentions-title::before, .mentions-title::after {
    content: &apos;&apos;; display: inline-block; width: 80px; height: 1px;
    background: #dde2e8; vertical-align: middle; margin: 0 10px;
  }


  /* MENTIONS GRID */
  .mentions-grid {
    display: grid; grid-template-columns: 1fr 1fr;
    gap: 10px; flex: 1;
  }


  .mention-row {
    display: flex; align-items: center; gap: 0;
    border-radius: 14px; overflow: hidden;
    position: relative;
    border: 2.5px solid transparent;
    background-clip: padding-box;
  }
  .mention-row:nth-child(1) { border-color: #FFD700; box-shadow: 0 3px 12px rgba(255,215,0,0.20); }
  .mention-row:nth-child(2) { border-color: #08a451; box-shadow: 0 3px 12px rgba(8,164,81,0.18); }
  .mention-row:nth-child(3) { border-color: #eb1f25; box-shadow: 0 3px 12px rgba(235,31,37,0.15); }
  .mention-row:nth-child(4) { border-color: #2596be; box-shadow: 0 3px 12px rgba(37,150,190,0.18); }


  .mention-row::before {
    content: &apos;&apos;; position: absolute;
    right: 0; top: 0; width: 5px; height: 100%;
    border-radius: 0 12px 12px 0;
  }
  .mention-row:nth-child(1)::before { background: #FFD700; }
  .mention-row:nth-child(2)::before { background: #08a451; }
  .mention-row:nth-child(3)::before { background: #eb1f25; }
  .mention-row:nth-child(4)::before { background: #2596be; }


  .mention-inner {
    display: flex; align-items: center; gap: 10px;
    background: #ffffff; width: 100%;
    padding: 10px 14px 10px 10px;
    flex-direction: row-reverse;
  }


  .mention-rank {
    width: 34px; height: 34px; border-radius: 50%;
    display: flex; align-items: center; justify-content: center;
    font-family: &apos;Inter&apos;, sans-serif;
    font-size: 14px; font-weight: 800; color: #fff; flex-shrink: 0;
  }
  .mention-row:nth-child(1) .mention-rank { background: linear-gradient(135deg, #d4a800, #FFD700); }
  .mention-row:nth-child(2) .mention-rank { background: linear-gradient(135deg, #08a451, #066e36); }
  .mention-row:nth-child(3) .mention-rank { background: linear-gradient(135deg, #eb1f25, #b8161c); }
  .mention-row:nth-child(4) .mention-rank { background: linear-gradient(135deg, #2596be, #1a7a9e); }


  .mention-photo {
    width: 88px; height: 88px;
    border-radius: 50%; overflow: hidden;
    flex-shrink: 0;
    box-shadow: 0 2px 8px rgba(0,0,0,0.13);
  }
  .mention-row:nth-child(1) .mention-photo { border: 3px solid #FFD700; }
  .mention-row:nth-child(2) .mention-photo { border: 3px solid #08a451; }
  .mention-row:nth-child(3) .mention-photo { border: 3px solid #eb1f25; }
  .mention-row:nth-child(4) .mention-photo { border: 3px solid #2596be; }
  .mention-photo img {
    width: 100%; height: 100%; object-fit: cover; object-position: top center; border-radius: 50%;
  }


  .mention-info { flex: 1; text-align: right; padding-right: 4px; }
  .mention-name {
    font-family: &apos;Noto Naskh Arabic&apos;, serif;
    font-size: 18px; font-weight: 700; color: #111827;
    line-height: 1.3;
  }
  .mention-class {
    font-family: &apos;Noto Naskh Arabic&apos;, serif;
    font-size: 12px; color: #08a451; margin-top: 1px;
  }


  .mention-marks {
    font-family: &apos;Inter&apos;, sans-serif;
    font-size: 20px; font-weight: 900; text-align: left; flex-shrink: 0; line-height: 1;
  }
  .mention-row:nth-child(1) .mention-marks { color: #b8860b; }
  .mention-row:nth-child(2) .mention-marks { color: #08a451; }
  .mention-row:nth-child(3) .mention-marks { color: #eb1f25; }
  .mention-row:nth-child(4) .mention-marks { color: #2596be; }
  .mention-marks span { font-size: 12px; font-weight: 500; color: #9ca3af; }


  /* QUOTE */
  .topper-quote {
    margin-top: 10px; padding-top: 10px;
    border-top: 1px solid #e5e9ee; text-align: center;
    font-family: &apos;Noto Naskh Arabic&apos;, serif;
    font-size: 16px; color: #9ca3af; font-style: italic;
  }
  .topper-quote i { color: #fcca13; margin: 0 5px; }


  /* ===== FOOTER ===== */
  .footer-container { width: 100%; flex-shrink: 0; }
  .footer-inner {
    background: linear-gradient(135deg, #083d22 0%, #08a451 50%, #083d22 100%);
    padding: 16px 44px 14px; position: relative; overflow: hidden;
  }
  .footer-inner::after {
    content: &apos;&apos;; position: absolute; inset: 0;
    background: radial-gradient(ellipse at 20% 50%, rgba(252,202,19,0.07) 0%, transparent 55%);
    pointer-events: none;
  }
  .footer-row {
    display: flex; align-items: center; justify-content: space-between;
    gap: 12px; position: relative; z-index: 2;
  }
  .footer-school-name {
    font-family: &apos;Noto Naskh Arabic&apos;, serif;
    font-size: 13px; font-weight: 700;
    color: rgba(255,255,255,0.92); white-space: nowrap; flex-shrink: 0;
  }
  .footer-divider { width: 1px; height: 36px; background: rgba(255,255,255,0.22); flex-shrink: 0; }
  .footer-contact { display: flex; align-items: center; gap: 18px; flex: 1; justify-content: center; }
  .footer-contact-item {
    display: flex; align-items: center; gap: 6px;
    color: rgba(255,255,255,0.84); white-space: nowrap; flex-direction: row-reverse;
  }
  .footer-contact-item i { color: #fcca13; font-size: 12px; flex-shrink: 0; }
  .footer-contact-item span { font-family: &apos;Noto Naskh Arabic&apos;, serif; font-size: 12px; }
  .footer-contact-item .latin {
    font-family: &apos;Inter&apos;, sans-serif; font-size: 11.5px; direction: ltr; unicode-bidi: embed;
  }
  .footer-social { display: flex; gap: 9px; flex-shrink: 0; }
  .footer-social a {
    width: 36px; height: 36px; border-radius: 50%;
    background: rgba(255,255,255,0.13); border: 1px solid rgba(255,255,255,0.20);
    display: flex; align-items: center; justify-content: center;
    color: #ffffff; font-size: 14px; text-decoration: none;
  }
  .footer-stripe { width: 100%; height: 7px; display: flex; }
  .footer-stripe span { flex: 1; }
  .footer-stripe span:nth-child(1) { background: #fcca13; }
  .footer-stripe span:nth-child(2) { background: #08a451; }
  .footer-stripe span:nth-child(3) { background: #eb1f25; }
  .footer-stripe span:nth-child(4) { background: #703336; }
&lt;/style&gt;
