  &lt;div class=&quot;body-container&quot;&gt;
    &lt;div class=&quot;body-card&quot;&gt;


      &lt;!-- META ROW: Teacher + Subject + Month + Class + Total Marks --&gt;
      &lt;div class=&quot;meta-row&quot;&gt;
        &lt;div class=&quot;meta-chip&quot;&gt;
          &lt;div class=&quot;meta-icon teacher&quot;&gt;&lt;i class=&quot;fas fa-chalkboard-teacher&quot;&gt;&lt;/i&gt;&lt;/div&gt;
