            &lt;div class=&quot;meta-chip-val&quot;&gt;{{teacher_name}}&lt;/div&gt;
          &lt;/div&gt;
        &lt;/div&gt;
        &lt;div class=&quot;meta-chip&quot;&gt;
          &lt;div class=&quot;meta-icon subject&quot;&gt;&lt;i class=&quot;fas fa-book-open&quot;&gt;&lt;/i&gt;&lt;/div&gt;
          &lt;div class=&quot;meta-chip-text&quot;&gt;
            &lt;div class=&quot;meta-chip-label&quot;&gt;مضمون&lt;/div&gt;
            &lt;div class=&quot;meta-chip-val&quot;&gt;{{subject}}&lt;/div&gt;
          &lt;/div&gt;
        &lt;/div&gt;
