          &lt;div class=&quot;meta-icon month&quot;&gt;&lt;i class=&quot;fas fa-calendar-alt&quot;&gt;&lt;/i&gt;&lt;/div&gt;
          &lt;div class=&quot;meta-chip-text&quot;&gt;
            &lt;div class=&quot;meta-chip-label&quot;&gt;مهينو&lt;/div&gt;
            &lt;div class=&quot;meta-chip-val&quot;&gt;{{month_year}}&lt;/div&gt;
